#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""One-off generator for s1_en/ko/ja.py — run then delete if desired."""

from pathlib import Path

ENTRIES = []  # populated below


def write_file(path: Path, lang: str, pairs):
    pairs = sorted(pairs, key=lambda x: len(x[0]), reverse=True)
    out = [
        "# -*- coding: utf-8 -*-",
        f'"""S1 zh → {lang} replacements for fomo-season-1.html."""',
        "",
        "REPLACEMENTS = [",
    ]
    for zh, tr in pairs:
        def esc(s: str) -> str:
            return s.replace("\\", "\\\\").replace('"', '\\"').replace("\n", "\\n")
        zh_esc, tr_esc = esc(zh), esc(tr)
        out.append(f'    ("{zh_esc}", "{tr_esc}"),')
    out.append("]")
    out.append("")
    path.write_text("\n".join(out), encoding="utf-8")
    print(f"{path}: {len(pairs)} tuples")


